(function(window,document){"use strict";window.lazySizesConfig=window.lazySizesConfig||{};lazySizesConfig.loadMode=1;lazySizesConfig.preloadAfterLoad=true;var lazyClass="lazyload",lazyLoaded="lazyloaded",lazyLoading="lazyloading";function unveilElement(el){if(el.tagName==="IMG"&&el.dataset.src){el.src=el.dataset.src;}if(el.dataset.srcset){el.srcset=el.dataset.srcset;}if(el.dataset.bg){el.style.backgroundImage="url('"+el.dataset.bg+"')";}el.classList.add(lazyLoading);el.addEventListener("load",function(){el.classList.remove(lazyLoading);el.classList.add(lazyLoaded);},{once:true});if(el.tagName!=="IMG"){el.classList.remove(lazyLoading);el.classList.add(lazyLoaded);}}function inViewport(el){var rect=el.getBoundingClientRect();return(rect.top<window.innerHeight+200&&rect.left<window.innerWidth+200&&rect.bottom>-200&&rect.right>-200);}function checkLazy(){var lazyElems=document.querySelectorAll("."+lazyClass+":not(."+lazyLoaded+")");lazyElems.forEach(function(el){if(inViewport(el)){unveilElement(el);}});}var active=false;function lazyCheck(){if(!active){active=true;requestAnimationFrame(function(){checkLazy();active=false;});}}document.addEventListener("scroll",lazyCheck,{passive:true});window.addEventListener("resize",lazyCheck,{passive:true});window.addEventListener("orientationchange",lazyCheck,{passive:true});document.addEventListener("DOMContentLoaded",checkLazy);})(window,document);
